import React, { useState, useEffect } from 'react';
import {
  Box,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  CircularProgress,
  Grid
} from '@mui/material';
import dashboardService from '../../services/dashboardService';

const HistoricoTrades = () => {
  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalTrades: 0,
    winRate: 0,
    totalPnl: 0,
    winningTrades: 0,
    losingTrades: 0
  });

  const loadTrades = async () => {
    try {
      setLoading(true);
      const response = await dashboardService.getClosedTrades();
      setTrades(response.trades || []);
      
      // Calcula estatísticas
      const totalTrades = response.trades.length;
      const winningTrades = response.trades.filter(trade => parseFloat(trade.pnl) > 0).length;
      const winRate = totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0;
      const totalPnl = response.trades.reduce((sum, trade) => sum + parseFloat(trade.pnl), 0);
      
      setStats({
        totalTrades,
        winRate,
        totalPnl,
        winningTrades,
        losingTrades: totalTrades - winningTrades
      });
    } catch (error) {
      console.error('Erro ao carregar trades:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadTrades();
  }, []);

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'USD'
    }).format(value);
  };

  const formatPercent = (value) => {
    return `${value.toFixed(2)}%`;
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" p={3}>
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ mt: 4, p: 2, bgcolor: 'background.paper', borderRadius: 1 }}>
      <Typography variant="h6" gutterBottom>
        Histórico de Trades
      </Typography>

      {/* Estatísticas */}
      <Grid container spacing={2} sx={{ mb: 3 }}>
        <Grid item xs={12} sm={6} md={2.4}>
          <Paper sx={{ p: 2, textAlign: 'center' }}>
            <Typography variant="subtitle2">Total de Trades</Typography>
            <Typography variant="h6">{stats.totalTrades}</Typography>
          </Paper>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Paper sx={{ p: 2, textAlign: 'center' }}>
            <Typography variant="subtitle2">Win Rate</Typography>
            <Typography variant="h6">{formatPercent(stats.winRate)}</Typography>
          </Paper>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Paper sx={{ p: 2, textAlign: 'center' }}>
            <Typography variant="subtitle2">PnL Total</Typography>
            <Typography variant="h6" color={stats.totalPnl >= 0 ? 'success.main' : 'error.main'}>
              {formatCurrency(stats.totalPnl)}
            </Typography>
          </Paper>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Paper sx={{ p: 2, textAlign: 'center' }}>
            <Typography variant="subtitle2">Trades Ganhos</Typography>
            <Typography variant="h6" color="success.main">{stats.winningTrades}</Typography>
          </Paper>
        </Grid>
        <Grid item xs={12} sm={6} md={2.4}>
          <Paper sx={{ p: 2, textAlign: 'center' }}>
            <Typography variant="subtitle2">Trades Perdidos</Typography>
            <Typography variant="h6" color="error.main">{stats.losingTrades}</Typography>
          </Paper>
        </Grid>
      </Grid>

      {/* Tabela de Trades */}
      <TableContainer component={Paper}>
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Par</TableCell>
              <TableCell>Lado</TableCell>
              <TableCell>Tamanho</TableCell>
              <TableCell>Alavancagem</TableCell>
              <TableCell>Preço de Entrada</TableCell>
              <TableCell>Preço de Saída</TableCell>
              <TableCell>PnL</TableCell>
              <TableCell>ROE%</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {trades.map((trade, index) => (
              <TableRow key={index}>
                <TableCell>{trade.symbol}</TableCell>
                <TableCell>
                  <Typography color={trade.side === 'buy' ? 'success.main' : 'error.main'}>
                    {trade.side === 'buy' ? 'Compra' : 'Venda'}
                  </Typography>
                </TableCell>
                <TableCell>{trade.size}</TableCell>
                <TableCell>{trade.leverage}x</TableCell>
                <TableCell>{formatCurrency(parseFloat(trade.entryPrice))}</TableCell>
                <TableCell>{formatCurrency(parseFloat(trade.exitPrice))}</TableCell>
                <TableCell>
                  <Typography color={parseFloat(trade.pnl) >= 0 ? 'success.main' : 'error.main'}>
                    {formatCurrency(parseFloat(trade.pnl))}
                  </Typography>
                </TableCell>
                <TableCell>
                  <Typography color={parseFloat(trade.roe) >= 0 ? 'success.main' : 'error.main'}>
                    {formatPercent(parseFloat(trade.roe))}
                  </Typography>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default HistoricoTrades;
